{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the aggregate root structure of the Shipment bounded context, affecting data models, external integrations, billing, routing, proof-of-delivery, and notification workflows. With 2 million existing shipments and external partner API contracts, this is not a trivial schema migration — it redefines what a Shipment *is*.",
    "bounded_context": "Shipment Fulfillment / Delivery Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "An aggregate root representing a single consignment moving from origin to one or more delivery points. Owns the lifecycle of all associated Recipients." },
      { "term": "Recipient", "definition": "A value object (now entity) representing a person or entity who receives part or all of a Shipment. Has a name, address, phone number, and delivery preferences." },
      { "term": "Delivery Preference", "definition": "Recipient-level configuration governing how and when delivery should occur (e.g., time window, safe place instructions, signature required, contactless)." },
      { "term": "Primary Recipient", "definition": "The first or default Recipient on a Shipment. Critical for backward compatibility — single-recipient shipments must still behave identically to the legacy model." },
      { "term": "Multi-drop Shipment", "definition": "A Shipment with more than one Recipient, each potentially at a different address, requiring route optimization across multiple stops." },
      { "term": "Shipment Status", "definition": "The overall lifecycle state of a Shipment. With multiple Recipients, this must now be derived from the individual delivery statuses of each Recipient's drop." },
      { "term": "Recipient Delivery Status", "definition": "The per-recipient fulfillment state (e.g., pending, out_for_delivery, delivered, failed). New concept required by the model change." },
      { "term": "Proof of Delivery (POD)", "definition": "Evidence that a delivery was completed. Must now be captured per-Recipient, not per-Shipment." },
      { "term": "Partner API", "definition": "External integration contracts that currently consume shipment data in the single-recipient format. These represent hard external constraints." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A Shipment with zero Recipients is physically meaningless — there is no delivery without a destination. This is a structural integrity constraint.",
      "testable_assertion": "Any attempt to create a Shipment with an empty Recipients collection, or to remove the last Recipient from a Shipment, MUST be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment MUST have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These three fields are the minimum data required to attempt a physical delivery and contact the recipient. Without them, fulfillment is impossible.",
      "testable_assertion": "Creating or updating a Recipient with a null/empty name, address, or phone number MUST be rejected at the domain level."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a single Shipment MUST have a unique address.",
      "invariant": true,
      "invariant_justification": "Two Recipients at the identical address on the same Shipment is a data integrity issue — it indicates a duplicate entry, not a legitimate multi-drop. If two people share an address, they should be a single delivery stop with multiple contact names.",
      "testable_assertion": "Adding a Recipient whose normalized address matches an existing Recipient on the same Shipment MUST be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Existing single-recipient Shipments MUST remain fully functional with no behavioral change after the model evolution.",
      "invariant": true,
      "invariant_justification": "2 million existing records and their associated business processes must not break. Backward compatibility is a data integrity constraint, not a preference.",
      "testable_assertion": "All existing Shipments with one Recipient MUST continue to return identical data and behavior through all existing APIs and workflows."
    },
    {
      "id": "BR-5",
      "rule": "Shipment-level status MUST be derived from the aggregate of all Recipient delivery statuses.",
      "invariant": true,
      "invariant_justification": "A Shipment cannot be 'delivered' if any Recipient's delivery has not been fulfilled. The overall state is a function of the parts — allowing manual override would corrupt the audit trail.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are 'delivered' and 1 is 'pending' MUST NOT have a Shipment-level status of 'delivered'. It should be 'partially_delivered' or equivalent."
    },
    {
      "id": "BR-6",
      "rule": "Delivery preferences are owned by each Recipient independently and do not cascade from the Shipment.",
      "invariant": false,
      "invariant_justification": "This is a product design decision. A future VP could decide to allow Shipment-level default preferences that Recipients inherit. The per-Recipient ownership is a policy, not a physical constraint.",
      "testable_assertion": "Changing one Recipient's delivery preference MUST NOT affect any other Recipient's preferences on the same Shipment."
    },
    {
      "id": "BR-7",
      "rule": "Proof of Delivery MUST be captured per Recipient, not per Shipment.",
      "invariant": true,
      "invariant_justification": "Each Recipient is a distinct physical delivery event. A signature at Address A does not prove delivery at Address B. Conflating POD across Recipients would make the audit trail legally unreliable.",
      "testable_assertion": "Each Recipient on a multi-drop Shipment MUST have an independent POD record. Marking one Recipient as delivered MUST NOT satisfy POD for others."
    },
    {
      "id": "BR-8",
      "rule": "External partner APIs MUST continue to receive single-recipient format until explicitly migrated.",
      "invariant": false,
      "invariant_justification": "This is a contractual and operational constraint, but it is time-bound. Partners will eventually migrate. It is a policy that will change, not a physical law.",
      "testable_assertion": "For any Shipment sent to a partner API that has not been migrated to the multi-recipient format, the payload MUST contain only the Primary Recipient and MUST match the current schema exactly."
    },
    {
      "id": "BR-9",
      "rule": "Notifications (SMS, email, tracking updates) MUST be sent independently to each Recipient based on their own delivery status and preferences.",
      "invariant": false,
      "invariant_justification": "Notification strategy is a product policy. A VP could decide to batch notifications or change channels. The independence is a preference, not a structural constraint.",
      "testable_assertion": "When Recipient A is delivered and Recipient B is pending, only Recipient A receives a delivery confirmation notification."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator provides two or more Recipients with distinct addresses and valid contact details",
      "then": "The Shipment is created with all Recipients persisted, each with their own delivery preferences, and the Shipment status is 'pending'"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment from production (legacy data)",
      "when": "It is queried through any existing API or workflow",
      "then": "It returns the same structure and data as before the model change, with no regressions"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where one Recipient has been delivered",
      "when": "The Shipment status is queried",
      "then": "The status reflects 'partially_delivered' (or domain-equivalent), not 'delivered'"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment",
      "when": "A courier completes delivery to one Recipient",
      "then": "Proof of Delivery is recorded for that Recipient only, and other Recipients remain in their current status"
    },
    {
      "id": "AC-5",
      "given": "A Shipment with two Recipients",
      "when": "A user attempts to remove the last remaining Recipient",
      "then": "The operation is rejected with a domain error — a Shipment must always have at least one Recipient"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient Shipment is synced to an external partner API that has not been migrated",
      "when": "The data is serialized for the partner",
      "then": "Only the Primary Recipient is included, in the legacy single-recipient format, and no data is lost"
    },
    {
      "id": "AC-7",
      "given": "A multi-recipient Shipment",
      "when": "Recipient B's delivery fails and Recipient A's succeeds",
      "then": "Recipient B receives a failure notification, Recipient A receives a success notification, and the Sender is informed of partial fulfillment"
    },
    {
      "id": "AC-8",
      "given": "2 million existing Shipments in production",
      "when": "The data migration runs",
      "then": "Each legacy Shipment's single Recipient is preserved as the sole entry in the new Recipients collection, marked as Primary Recipient, with no data loss or transformation errors"
    },
    {
      "id": "AC-9",
      "given": "A Shipment creation request",
      "when": "Two Recipients have the same normalized address",
      "then": "The request is rejected with a clear domain error indicating duplicate delivery addresses"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where one Recipient's address becomes invalid after creation (e.g., address correction service flags it)",
      "expected_behavior": "The affected Recipient is flagged for address resolution. Other Recipients' deliveries proceed unaffected. Shipment status reflects the partial blockage."
    },
    {
      "scenario": "All Recipients on a multi-drop Shipment have different delivery time windows that are mutually incompatible for a single courier route",
      "expected_behavior": "Route optimization should flag the conflict at creation time or planning stage. The system must not silently accept an undeliverable Shipment."
    },
    {
      "scenario": "An external partner API receives a multi-recipient Shipment but only supports single-recipient format",
      "expected_behavior": "The anti-corruption layer maps to Primary Recipient only. The system logs a warning and surfaces it to operations so they know the partner has incomplete data."
    },
    {
      "scenario": "A Recipient is added to a Shipment that is already in-transit",
      "expected_behavior": "Domain must define whether mid-transit Recipient addition is allowed. If allowed, route must be recalculated. If not allowed, the operation is rejected with a clear lifecycle constraint error."
    },
    {
      "scenario": "A Shipment has 50+ Recipients (bulk/distribution scenario)",
      "expected_behavior": "The system must enforce a maximum Recipient count per Shipment (business policy, not invariant) to prevent abuse and ensure route feasibility. Suggested: escalate to product for threshold definition."
    },
    {
      "scenario": "Billing for a multi-recipient Shipment — is it one charge or per-recipient?",
      "expected_behavior": "This is a pricing model decision with major revenue impact. Must be explicitly defined before implementation. Current single-recipient billing logic must not silently undercharge multi-drop shipments."
    },
    {
      "scenario": "Partial cancellation — one Recipient cancels but others remain",
      "expected_behavior": "The cancelled Recipient is removed from the delivery plan. If it was the Primary Recipient, a new Primary must be designated. Shipment continues for remaining Recipients."
    },
    {
      "scenario": "Legacy reporting dashboards and analytics that aggregate by Shipment assume 1:1 with Recipient",
      "expected_behavior": "Reports counting 'deliveries' as equal to 'shipments' will undercount. Analytics must be updated or a compatibility view must be provided."
    }
  ],

  "business_impact": {
    "financial": "HIGH. Multi-recipient shipments introduce a new pricing dimension. If billing is not updated, multi-drop shipments will be charged at single-delivery rates, causing revenue leakage. Conversely, this feature enables higher-value shipment types (e.g., distribution runs, multi-stop B2B deliveries) that can command premium pricing. Migration costs include engineering effort, data migration risk, and partner re-integration.",
    "operational": "HIGH. Route optimization must evolve from single-stop to multi-stop per shipment. Courier workflows change — drivers now need per-recipient instructions and per-stop POD capture. Dispatch and operations dashboards must surface partial delivery states. Support teams need training on new Shipment lifecycle states (partially_delivered, partially_failed).",
    "user": "MEDIUM-HIGH. Senders gain flexibility to address multiple Recipients in a single Shipment. Recipients benefit from individualized delivery preferences. However, tracking UX becomes more complex — a Recipient should only see their own delivery status, not other Recipients'. Couriers face a more complex pickup-to-delivery flow.",
    "risk": "HIGH. Data migration of 2M records is non-trivial. External partner API compatibility is a hard constraint — any regression breaks contractual obligations. The Shipment aggregate grows in complexity, increasing the surface area for bugs in status derivation, billing, and notification logic. If the Recipient entity identity is not handled carefully, orphaned or duplicate Recipients could corrupt the data model.",
    "stakeholders_affected": [
      { "group": "Senders (Shippers)", "impact": "Gain ability to ship to multiple recipients in one transaction. Must understand new pricing model. Existing single-recipient workflows must not break." },
      { "group": "Recipients", "impact": "Receive individualized delivery preferences and notifications. Privacy concern: one Recipient must not see other Recipients' data on the same Shipment." },
      { "group": "Couriers/Drivers", "impact": "Multi-stop delivery workflow per Shipment. Need updated mobile apps for per-Recipient POD capture. Route planning changes." },
      { "group": "Operations/Dispatch", "impact": "New Shipment states to monitor (partially_delivered). Dashboard and alerting changes. Increased complexity in exception handling." },
      { "group": "External Partners", "impact": "API contract changes required eventually. In interim, they receive degraded data (Primary Recipient only). Risk of data inconsistency if not managed via anti-corruption layer." },
      { "group": "Finance/Billing", "impact": "Must define multi-recipient pricing model before launch. Revenue recognition per-delivery-stop may be required. Existing invoicing assumes 1 Shipment = 1 delivery." },
      { "group": "Customer Support", "impact": "Must handle queries about partial deliveries, per-Recipient status, and split-Shipment scenarios. Training and tooling updates needed." },
      { "group": "Product/Analytics", "impact": "All KPIs built on Shipment = 1 delivery are invalidated. Delivery success rate, on-time percentage, and volume metrics must be redefined." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is directionally clear but critically incomplete on several dimensions that have major downstream impact. Billing model for multi-recipient shipments is undefined. Maximum Recipient count is unspecified. Whether Recipients can be added/removed mid-lifecycle is unstated. The 'delivery preferences' concept is mentioned but not enumerated. Partner API migration timeline and strategy are absent. These gaps mean acceptance criteria are reasonable but may need revision once ambiguities are resolved.",
    "high_confidence_areas": [
      "The 1:N relationship between Shipment and Recipient is the correct model evolution",
      "Backward compatibility for 2M existing records is a hard requirement",
      "Per-Recipient POD and notification are structurally necessary",
      "External partner API compatibility layer is required",
      "Shipment status must be derived from Recipient-level statuses"
    ],
    "low_confidence_areas": [
      "Billing model for multi-recipient Shipments — not defined in spec",
      "Maximum number of Recipients per Shipment — no guidance",
      "Whether Recipients can be modified after Shipment enters transit",
      "What 'delivery preferences' specifically includes",
      "Privacy model — can a Recipient see other Recipients on same Shipment?",
      "How existing analytics and reporting should adapt"
    ],
    "assumptions": [
      "The first/original Recipient on a multi-recipient Shipment is designated as 'Primary Recipient' for backward compatibility",
      "Recipient address uniqueness within a Shipment is enforced (not explicitly stated but implied by multi-drop semantics)",
      "External partner APIs are read-only consumers of Shipment data, not bi-directional",
      "The migration will be online (no downtime) given the 2M record volume"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec mentions 'delivery preferences' per Recipient but does not enumerate what preferences exist. Time windows? Signature required? Safe place? Contactless? The domain model for DeliveryPreference cannot be built without this definition.",
      "affected_stakeholders": ["Product", "Engineering", "Recipients", "Couriers"],
      "options": [
        "A) Define a fixed set of delivery preferences now (time window, signature, safe place, contactless)",
        "B) Make DeliveryPreference an extensible key-value model that product can evolve",
        "C) Ship with no preferences initially, add them incrementally"
      ],
      "recommendation": "Option A — define the initial set explicitly. Option B risks schemaless drift. Option C ships an incomplete feature."
    },
    {
      "type": "missing_context",
      "description": "No billing model defined for multi-recipient Shipments. This is a revenue-critical gap. Is it priced per-Shipment (flat), per-Recipient (per-stop), distance-based across all stops, or a hybrid? Implementation cannot proceed without this.",
      "affected_stakeholders": ["Finance", "Product", "Senders", "Engineering"],
      "options": [
        "A) Per-Recipient pricing (each stop is a billable delivery)",
        "B) Per-Shipment flat rate regardless of Recipient count",
        "C) Tiered pricing based on Recipient count brackets"
      ],
      "recommendation": "Option A — per-Recipient pricing aligns with operational cost reality (each stop costs driver time and fuel). But this is a business decision, not a domain one. Needs Finance/Product sign-off."
    },
    {
      "type": "ambiguity",
      "description": "Can Recipients be added or removed from a Shipment after it enters transit? This determines whether the Recipients collection is mutable throughout the Shipment lifecycle or only during certain states.",
      "affected_stakeholders": ["Product", "Operations", "Couriers", "Engineering"],
      "options": [
        "A) Recipients are immutable once Shipment is confirmed/dispatched",
        "B) Recipients can be added/removed at any lifecycle stage",
        "C) Recipients can be cancelled but not added mid-transit"
      ],
      "recommendation": "Option C — allows cancellation flexibility while preventing mid-route additions that would invalidate optimized routes. But needs product confirmation."
    },
    {
      "type": "ambiguity",
      "description": "Is there a maximum number of Recipients per Shipment? Without a cap, the system is vulnerable to abuse, performance degradation in route optimization, and operationally infeasible delivery plans.",
      "affected_stakeholders": ["Product", "Engineering", "Operations", "Couriers"],
      "options": [
        "A) Hard cap at a small number (e.g., 5-10) for initial launch",
        "B) No cap, rely on pricing to disincentivize large counts",
        "C) Configurable per-customer limit based on service tier"
      ],
      "recommendation": "Option A for launch — start conservative, expand based on operational learning. A courier physically cannot do 50 stops in a shift."
    },
    {
      "type": "missing_context",
      "description": "Recipient privacy model is undefined. On a multi-recipient Shipment, can Recipient A see that Recipient B exists? Can the Sender see all Recipients' statuses? Tracking page design depends entirely on this.",
      "affected_stakeholders": ["Recipients", "Product", "Legal/Compliance", "Engineering"],
      "options": [
        "A) Each Recipient sees only their own delivery status and tracking",
        "B) All Recipients can see the full Shipment including other Recipients",
        "C) Sender sees all; each Recipient sees only their own"
      ],
      "recommendation": "Option C — Sender has full visibility as the paying customer, while Recipient privacy is preserved. This aligns with standard logistics practice and likely GDPR expectations."
    }
  ],

  "rejection_reasons": []
}

